import{_ as t,o,c as r,ag as s}from"./chunks/framework.BD8VCRzL.js";const c=JSON.parse('{"title":"Welcome to Aurelius Ledger","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/index.md","filePath":"getting-started/index.md"}'),a={name:"getting-started/index.md"};function i(n,e,l,u,h,d){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="welcome-to-aurelius-ledger" tabindex="-1">Welcome to Aurelius Ledger <a class="header-anchor" href="#welcome-to-aurelius-ledger" aria-label="Permalink to &quot;Welcome to Aurelius Ledger&quot;">​</a></h1><p>Aurelius Ledger is your trading companion. It helps you track trades, monitor your mental state, and catch bad habits before they cost you money.</p><p>This guide walks you through everything you need to get the most out of your sessions.</p><h2 id="what-aurelius-ledger-does" tabindex="-1">What Aurelius Ledger Does <a class="header-anchor" href="#what-aurelius-ledger-does" aria-label="Permalink to &quot;What Aurelius Ledger Does&quot;">​</a></h2><ul><li><strong>Logs your trades</strong> from natural language — just type what happened</li><li><strong>Scores your discipline and agency</strong> — are you trading your plan or reacting emotionally?</li><li><strong>Watches for tilt</strong> — catches revenge trading, fear, and frustration patterns</li><li><strong>Shows you trends</strong> — see how your psychology evolves throughout the session</li></ul><h2 id="quick-links" tabindex="-1">Quick Links <a class="header-anchor" href="#quick-links" aria-label="Permalink to &quot;Quick Links&quot;">​</a></h2><ul><li><strong><a href="./setup">Setup Guide</a></strong> — Create your account and log your first trade</li><li><strong><a href="/help/features/trade-logging">Trade Logging</a></strong> — How to describe your trades</li><li><strong><a href="/help/features/dashboard">Dashboard Guide</a></strong> — Understanding your charts and stats</li><li><strong><a href="/help/features/ai-insights">AI Insights</a></strong> — How the AI coach works</li><li><strong><a href="/help/faq/">FAQ</a></strong> — Common questions</li></ul><h2 id="who-this-is-for" tabindex="-1">Who This Is For <a class="header-anchor" href="#who-this-is-for" aria-label="Permalink to &quot;Who This Is For&quot;">​</a></h2><p>You trade futures — NQ, ES, RTY, or CL. You&#39;ve got a strategy, but sometimes emotions get the better of you. You want to get better at staying disciplined and making decisions with intention, not reaction.</p><p>If that sounds like you, Aurelius Ledger is built for you.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><ol><li><strong>Log a trade</strong> — Type what happened in plain English</li><li><strong>The AI reads your description</strong> — It figures out direction, outcome, P&amp;L, and how disciplined you were</li><li><strong>You see the results</strong> — Charts update instantly showing your P&amp;L, discipline, and agency over time</li><li><strong>The coach chimes in</strong> — After enough trades, AI insights start appearing</li></ol><p>It is that simple. No forms to fill out, no dropdowns to manage. Just type and move on with your session.</p><h2 id="the-psychology-stuff" tabindex="-1">The Psychology Stuff <a class="header-anchor" href="#the-psychology-stuff" aria-label="Permalink to &quot;The Psychology Stuff&quot;">​</a></h2><p>Aurelius Ledger tracks two scores:</p><ul><li><strong>Discipline</strong> — Did you wait for your setup? Did you follow your rules?</li><li><strong>Agency</strong> — Are you in control of your decisions, or are you reacting to the market?</li></ul><p>Both scores range from -1 to +1. The system watches for patterns — like taking trades after a loss to &quot;make it back&quot; — and gives you a heads up before things get worse.</p><div class="tip custom-block"><p class="custom-block-title">This Is Not About Perfection</p><p>You will not score +1 every trade. Nobody does. The point is awareness. The more you see your patterns, the more you can work on them.</p></div><p>Ready to get started? Head to the <a href="./setup">Setup Guide</a>.</p>',19)])])}const p=t(a,[["render",i]]);export{c as __pageData,p as default};
